try:
    # Generic data access helper. Input is User data key data_access_input.
    request = User.getData("data_access_input")
    if request == None:
        raise Exception("Missing data_access_input")

    scope = request.get("scope")
    operation = request.get("operation")
    key = request.get("key")
    value = request.get("value")
    default_value = request.get("default")
    target_user = request.get("user")

    if key == None or key == "":
        raise Exception("Data access key is required")

    result = None

    if scope == "bot":
        if operation == "get":
            result = Bot.getData(key)
            if result == None:
                result = default_value
        elif operation == "save":
            Bot.saveData(key, value)
            result = value
        else:
            raise Exception("Unsupported bot data operation")

    elif scope == "user":
        if operation == "get":
            if target_user == None:
                result = User.getData(key)
            else:
                result = User.getData(key, user=target_user)
            if result == None:
                result = default_value
        elif operation == "save":
            if target_user == None:
                User.saveData(key, value)
            else:
                User.saveData(key, value, user=target_user)
            result = value
        else:
            raise Exception("Unsupported user data operation")
    else:
        raise Exception("Unsupported data scope")

    User.saveData("data_access_result", {"ok": True, "key": key, "value": result})
    User.deleteData("data_access_input")

except Exception as e:
    User.saveData("data_access_result", {"ok": False, "error": str(e)})
    User.saveData("error_context", {"command": "foundation_data_access", "error": str(e)})
    Bot.runCommand("foundation_error_log")

try:
    # Permission checker. Input is User data key permission_input.
    request = User.getData("permission_input")
    if request == None:
        raise Exception("Missing permission_input")

    admin_id = str(request.get("admin_id", u))
    permission = request.get("permission")
    if permission == None or permission == "":
        raise Exception("Permission is required")

    roles_by_admin = Bot.getData("iwms_admin_roles")
    if roles_by_admin == None:
        roles_by_admin = {}

    role_permissions = Bot.getData("iwms_role_permissions")
    if role_permissions == None:
        role_permissions = {}

    roles = roles_by_admin.get(admin_id, [])
    if admin_id in SUPER_ADMIN_IDS or admin_id in ADMIN_IDS:
        if "Super Admin" not in roles:
            roles.append("Super Admin")

    allowed = False
    matched_roles = []

    for role in roles:
        perms = role_permissions.get(role, [])
        if "*" in perms or permission in perms:
            allowed = True
            matched_roles.append(role)

    User.saveData("permission_result", {"ok": True, "allowed": allowed, "admin_id": admin_id, "permission": permission, "roles": roles, "matched_roles": matched_roles})
    User.deleteData("permission_input")

except Exception as e:
    User.saveData("permission_result", {"ok": False, "allowed": False, "error": str(e)})
    User.saveData("error_context", {"command": "foundation_permissions", "error": str(e)})
    Bot.runCommand("foundation_error_log")

try:
    # Reads the effective versioned policy for a requested week.
    request = User.getData("policy_input")
    if request == None:
        raise Exception("Missing policy_input")

    policy_type = request.get("policy_type")
    week_id = request.get("week_id")
    if policy_type not in ["comp", "review"]:
        raise Exception("policy_type must be comp or review")

    index_key = policy_type + "_policy_versions"
    versions = Bot.getData(index_key)
    if versions == None or len(versions) == 0:
        raise Exception("No policy versions configured for " + policy_type)

    selected_version = None
    for version in versions:
        policy = Bot.getData(policy_type + "_policy:" + str(version))
        if policy != None:
            effective_week = policy.get("effective_from_week_id")
            if week_id == None or effective_week == None or str(effective_week) <= str(week_id):
                selected_version = version

    if selected_version == None:
        selected_version = versions[0]

    selected_policy = Bot.getData(policy_type + "_policy:" + str(selected_version))
    User.saveData("policy_result", {"ok": True, "policy_type": policy_type, "version": selected_version, "policy": selected_policy})
    User.deleteData("policy_input")

except Exception as e:
    User.saveData("policy_result", {"ok": False, "error": str(e)})
    User.saveData("error_context", {"command": "foundation_policy_reader", "error": str(e)})
    Bot.runCommand("foundation_error_log")

try:
    # Admin navigation stack helper with max depth 20 and FIFO eviction.
    request = User.getData("workspace_context_input")
    if request == None:
        raise Exception("Missing workspace_context_input")

    operation = request.get("operation")
    entry = request.get("entry")
    stack = User.getData("admin_nav_stack")
    if stack == None:
        stack = []

    result = None
    if operation == "push":
        if entry == None:
            raise Exception("Workspace context entry is required for push")
        stack.append(entry)
        if len(stack) > 20:
            stack = stack[len(stack) - 20:len(stack)]
        User.saveData("admin_nav_stack", stack)
        result = entry
    elif operation == "pop":
        if len(stack) == 0:
            result = None
        else:
            result = stack.pop()
            User.saveData("admin_nav_stack", stack)
    elif operation == "clear":
        stack = []
        User.saveData("admin_nav_stack", stack)
        result = None
    elif operation == "peek":
        if len(stack) == 0:
            result = None
        else:
            result = stack[len(stack) - 1]
    else:
        raise Exception("Unsupported workspace context operation")

    User.saveData("workspace_context_result", {"ok": True, "operation": operation, "result": result, "stack": stack})
    User.deleteData("workspace_context_input")

except Exception as e:
    User.saveData("workspace_context_result", {"ok": False, "error": str(e)})
    User.saveData("error_context", {"command": "foundation_workspace_context", "error": str(e)})
    Bot.runCommand("foundation_error_log")

try:
    # Resolves current worker state into the next command to render on re-entry.
    profile = User.getData("worker_profile")
    if profile == None:
        result = {"ok": True, "next_command": "onboarding_language", "reason": "new_worker"}
    else:
        status = profile.get("status", "New")
        stage = profile.get("stage", "")
        resume_point = profile.get("resume_point", {})

        if status == "New":
            next_command = "onboarding_language"
        elif status == "Applying":
            if stage == "instagram_collection":
                next_command = "onboarding_ig_collect_resume"
            else:
                next_command = "onboarding_intro"
        elif status == "Training" or status == "VerificationPending":
            next_command = "onboarding_training_resume"
        elif status == "Active":
            next_command = "work_dashboard"
        elif status == "Paused":
            next_command = "worker_pause_screen"
        elif status == "Removed" or status == "AppealPending":
            next_command = "appeal_status_screen"
        elif status == "Deleted":
            next_command = "worker_deleted_status"
        else:
            next_command = "work_dashboard"

        result = {"ok": True, "next_command": next_command, "status": status, "stage": stage, "resume_point": resume_point}

    User.saveData("resume_result", result)

except Exception as e:
    User.saveData("resume_result", {"ok": False, "error": str(e)})
    User.saveData("error_context", {"command": "foundation_resume_engine", "error": str(e)})
    Bot.runCommand("foundation_error_log")
